// assets/bg-pattern.js
// Parametric SVG background pattern (ribbon / interlock style).
// Generated by geometry rules (NO bitmap / NO tracing).
// Stack: glow(z0) < pattern(z1) < content(z2)

(function () {
  try {
    var SVG_NS = "http://www.w3.org/2000/svg";

    function isFiniteNumber(n) {
      return typeof n === "number" && n === n && n !== Infinity && n !== -Infinity;
    }

    function cssVar(name) {
      try {
        return getComputedStyle(document.documentElement).getPropertyValue(name) || "";
      } catch (_) {
        return "";
      }
    }

    function num(v, fallback) {
      v = (v || "").trim();
      if (!v) return fallback;
      var n = parseFloat(v);
      return isFiniteNumber(n) ? n : fallback;
    }

    function int(v, fallback) {
      v = (v || "").trim();
      if (!v) return fallback;
      var n = parseInt(v, 10);
      return isFiniteNumber(n) ? n : fallback;
    }

    function createEl(tag, attrs, parent) {
      var el = document.createElementNS(SVG_NS, tag);
      if (attrs) {
        for (var k in attrs) {
          if (Object.prototype.hasOwnProperty.call(attrs, k)) {
            el.setAttribute(k, String(attrs[k]));
          }
        }
      }
      if (parent) parent.appendChild(el);
      return el;
    }

    function clearChildren(node) {
      while (node.firstChild) node.removeChild(node.firstChild);
    }

    function run() {
      if (!document.body) return void setTimeout(run, 0);

      // --- remove old canvas version if present ---
      var oldCanvas = document.getElementById("bg-pattern-canvas");
      if (oldCanvas && oldCanvas.parentNode) {
        oldCanvas.parentNode.removeChild(oldCanvas);
      }

      // --- ensure svg ---
      var svg = document.getElementById("bg-pattern-svg");
      if (!svg) {
        svg = document.createElementNS(SVG_NS, "svg");
        svg.id = "bg-pattern-svg";
        svg.setAttribute("aria-hidden", "true");
        svg.setAttribute("focusable", "false");
        svg.setAttribute("preserveAspectRatio", "none");
        document.body.insertBefore(svg, document.body.firstChild);
      }

      // --- force layer styles (never break layout) ---
      var st = svg.style;
      st.position = "fixed";
      st.inset = "0";
      st.width = "100vw";
      st.height = "100vh";
      st.pointerEvents = "none";
      st.zIndex = "1";
      st.display = "block";
      st.mixBlendMode = "normal";
      // Stroke color uses currentColor
      st.color = "var(--bg-pattern-color, #fff)";

      // enforce content z=2 (guarantees stack)
      try {
        [".site-header", ".page-content", ".site-footer"].forEach(function (sel) {
          var el = document.querySelector(sel);
          if (el) {
            if (!el.style.position) el.style.position = "relative";
            el.style.zIndex = "2";
          }
        });
      } catch (_) {}

      // ==========================
      // TUNING (editable)
      // ==========================
      // You can override via CSS variables on :root:
      // --bg-pattern-color, --bg-pattern-opacity
      // --bg-pattern-cell, --bg-pattern-shear, --bg-pattern-rails, --bg-pattern-gap
      // --bg-pattern-stroke, --bg-pattern-radius, --bg-pattern-xmid, --bg-pattern-step
      // --bg-pattern-ya, --bg-pattern-yb

      var CELL = num(cssVar("--bg-pattern-cell"), 260);     // base cell size (px)
      var SHEAR = num(cssVar("--bg-pattern-shear"), 1.0);   // 1.0 => 45deg (y += x)
      var RAILS = int(cssVar("--bg-pattern-rails"), 4);     // parallel lines count
      var GAP = num(cssVar("--bg-pattern-gap"), 10);        // spacing between rails
      var STROKE = num(cssVar("--bg-pattern-stroke"), 1.6); // line width
      var R = num(cssVar("--bg-pattern-radius"), 36);       // corner radius

      // fractions of CELL
      var X_MID = num(cssVar("--bg-pattern-xmid"), 0.55) * CELL; // where the vertical "drop" occurs
      var STEP = num(cssVar("--bg-pattern-step"), 0.55) * CELL;  // vertical drop length
      var Y_A = num(cssVar("--bg-pattern-ya"), 0.25) * CELL;     // start y (one ribbon)
      var Y_B = num(cssVar("--bg-pattern-yb"), 0.75) * CELL;     // start y (other ribbon)

      // sanity clamps
      CELL = Math.max(120, Math.min(520, CELL));
      SHEAR = Math.max(-2.0, Math.min(2.0, SHEAR));
      RAILS = Math.max(1, Math.min(8, RAILS));
      GAP = Math.max(2, Math.min(24, GAP));
      STROKE = Math.max(0.6, Math.min(4.0, STROKE));

      // clamp radius so arcs don't invert
      var maxR = Math.min(
        R,
        Math.max(0, X_MID - 1),
        Math.max(0, CELL - X_MID - 1),
        Math.max(0, STEP / 2 - 1)
      );
      R = Math.max(0, maxR);

      // pattern tile size (2x2 brick unit)
      var PAT_W = CELL * 2;
      var PAT_H = CELL * 2;

      // rebuild svg content (static)
      clearChildren(svg);

      var defs = createEl("defs", null, svg);

      // Shear transform: x' = x, y' = y + SHEAR*x
      // => horizontal becomes diagonal, vertical stays vertical (key property)
      var pattern = createEl(
        "pattern",
        {
          id: "bgPattern",
          patternUnits: "userSpaceOnUse",
          patternContentUnits: "userSpaceOnUse",
          width: PAT_W,
          height: PAT_H,
          patternTransform: "matrix(1 " + SHEAR + " 0 1 0 0)",
        },
        defs
      );

      var g = createEl("g", null, pattern);
      g.setAttribute("fill", "none");
      g.setAttribute("stroke", "currentColor");
      g.setAttribute("stroke-width", String(STROKE));
      g.setAttribute("stroke-linecap", "round");
      g.setAttribute("stroke-linejoin", "round");
      g.setAttribute("shape-rendering", "geometricPrecision");
      g.style.opacity = "var(--bg-pattern-opacity, 1)";

      function ribbonPath(y0, dir, o) {
        // Base coordinate: (horizontal run) -> (vertical) -> (horizontal run)
        // After shear: horizontal run becomes 45deg diagonal, vertical stays vertical.
        // dir: +1 (down) or -1 (up)
        var x0 = 0;
        var y1 = y0 + o;
        var x1 = X_MID;
        var y2 = y0 + dir * STEP + o;
        var x2 = CELL;

        if (R <= 0.001) {
          return "M " + x0 + " " + y1 + " L " + x1 + " " + y1 + " L " + x1 + " " + y2 + " L " + x2 + " " + y2;
        }

        // Arc sweep flags (SVG screen coords: y down)
        // right -> down  : sweep=1
        // right -> up    : sweep=0
        // down  -> right : sweep=0
        // up    -> right : sweep=1
        var sweep1 = dir > 0 ? 1 : 0;
        var sweep2 = dir > 0 ? 0 : 1;

        return [
          "M", x0, y1,
          "L", (x1 - R), y1,
          "A", R, R, 0, 0, sweep1, x1, (y1 + dir * R),
          "L", x1, (y2 - dir * R),
          "A", R, R, 0, 0, sweep2, (x1 + R), y2,
          "L", x2, y2
        ].join(" ");
      }

      function addTile(tx, ty, phase) {
        // phase toggles which ribbon bends down/up => interlocking feel
        var tile = createEl("g", { transform: "translate(" + tx + " " + ty + ")" }, g);

        for (var i = 0; i < RAILS; i++) {
          var o = (i - (RAILS - 1) / 2) * GAP;

          var dirA = phase === 0 ? 1 : -1;
          var yA = dirA > 0 ? Y_A : Y_B;
          createEl("path", { d: ribbonPath(yA, dirA, o) }, tile);

          var dirB = -dirA;
          var yB = dirA > 0 ? Y_B : Y_A;
          createEl("path", { d: ribbonPath(yB, dirB, o) }, tile);
        }
      }

      // Overscan drawing for seam-free tiling even if pattern gets clipped by browser
      var start = -CELL;
      var endX = PAT_W + CELL;
      var endY = PAT_H + CELL;

      var row = 0;
      for (var y = start; y <= endY; y += CELL, row++) {
        var xOffset = (row % 2) * (CELL * 0.5); // brick staggering
        var col = 0;
        for (var x = start; x <= endX; x += CELL, col++) {
          var phase = (row + col) % 2;
          addTile(x + xOffset, y, phase);
        }
      }

      var rect = createEl("rect", { id: "bg-pattern-rect", x: 0, y: 0, fill: "url(#bgPattern)" }, svg);

      function resize() {
        var w = Math.max(1, Math.ceil(window.innerWidth));
        var h = Math.max(1, Math.ceil(window.innerHeight));
        svg.setAttribute("viewBox", "0 0 " + w + " " + h);
        svg.setAttribute("width", String(w));
        svg.setAttribute("height", String(h));
        rect.setAttribute("width", String(w));
        rect.setAttribute("height", String(h));
      }

      resize();

      var rto = 0;
      window.addEventListener(
        "resize",
        function () {
          clearTimeout(rto);
          rto = setTimeout(resize, 100);
        },
        { passive: true }
      );
    }

    if (document.readyState === "loading") {
      document.addEventListener("DOMContentLoaded", run, { once: true });
    } else {
      run();
    }
  } catch (e) {
    console.error("[bg-pattern] error", e);
  }
})();
